// ═══════════════════════════════════════════════════════════════════════════
// AGG - Final aggregation of calculation results + FREE DEMO info
// ═══════════════════════════════════════════════════════════════════════════

const cfg = $('Config').first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');
const session = sd.sess?.[cid] || {};

const L = cfg.L || {};
let total = 0, workers_sum = 0, materials_sum = 0, machines_sum = 0, labor_hours_sum = 0;
let found_count = 0;

// Get accumulated results
const storedResults = sd.res?.[cid] || [];

console.log('=== AGG ===');
console.log('Results count:', storedResults.length);

// Process each result
const works = storedResults.map(w => {
  const uc = w.uc || 0;
  const tc = w.tc || 0;

  total += tc;
  workers_sum += (w.workers_total || 0);
  materials_sum += (w.materials_total || 0);
  machines_sum += (w.machines_total || 0);
  labor_hours_sum += (w.labor_hours || 0);

  if (w._found) found_count++;

  return {
    id: w.id,
    name: w.name || w.sq,
    query: w.sq || w.query,
    qty: w.qty,
    unit: w.unit,
    room: w.room,
    uc: uc,
    tc: tc,
    rate_code: w.rate_code || '',
    rate_name: w.rate_name || '',
    resources: w.resources || [],
    workers_total: w.workers_total || 0,
    materials_total: w.materials_total || 0,
    machines_total: w.machines_total || 0,
    labor_hours: w.labor_hours || 0,
    found: w._found || false,
    scope_of_work: w.scope_of_work || [],
    original_query: w.original_query || w.name
  };
});

const pct = works.length > 0 ? Math.round(found_count / works.length * 100) : 0;

// FREE DEMO info
const isLimited = session.isLimited || false;
const originalTotal = session.totalWorks || works.length;
const skippedWorks = originalTotal - works.length;

console.log('Calculated:', works.length, '/', originalTotal);
console.log('Found:', found_count, '/', works.length);
console.log('Total cost:', total.toFixed(2));
console.log('Limited:', isLimited);

// Cleanup staticData
if (sd.res?.[cid]) delete sd.res[cid];
if (sd.calcProgress?.[cid]) delete sd.calcProgress[cid];
if (sd.progress?.[cid]) delete sd.progress[cid];

// Save for report generation
sd.lastResults = { works, total, workers_sum, materials_sum, machines_sum, labor_hours_sum, found_count, pct, L };

return {
  json: {
    chatId: cid,
    bot_token: cfg.bot_token,
    works: works,
    total: Math.round(total * 100) / 100,
    workers_sum: Math.round(workers_sum * 100) / 100,
    materials_sum: Math.round(materials_sum * 100) / 100,
    machines_sum: Math.round(machines_sum * 100) / 100,
    labor_hours_sum: Math.round(labor_hours_sum * 100) / 100,
    found_count: found_count,
    total_count: works.length,
    pct: pct,
    L: L,
    currency: L.sym || '€',
    description: session.description || '',
    // FREE DEMO
    _is_limited: isLimited,
    _total_works: originalTotal,
    _skipped_works: skippedWorks
  }
};

// ═══════════════════════════════════════════════════════════════════════════
// PREP CLEANUP - Prepare message IDs for deletion after loop completes
// ═══════════════════════════════════════════════════════════════════════════

const cfg = $('Config').first().json;
const sd = $getWorkflowStaticData('global');
const cid = String(cfg.chatId);

// Get message IDs to delete
const lastMsgId = sd.calcProgress?.[cid]?.lastMsgId || null;
const progressMsgId = sd.progress?.[cid]?.message_id || null;

console.log('=== PREP CLEANUP ===');
console.log('ChatId:', cid);
console.log('Work msg:', lastMsgId);
console.log('Progress msg:', progressMsgId);

return {
  json: {
    chatId: cfg.chatId,
    bot_token: cfg.bot_token,
    L: cfg.L,
    _delete_work_msg: lastMsgId,
    _delete_progress_msg: progressMsgId
  }
};

// ═══════════════════════════════════════════════════════════════════════════
// ACC - Accumulate calculation results for final aggregation
// ═══════════════════════════════════════════════════════════════════════════

const sd = $getWorkflowStaticData('global');
const w = $('📊 Update Result').first().json;
const cid = String(w.chatId);

if (!sd.res) sd.res = {};
if (!sd.res[cid]) sd.res[cid] = [];
sd.res[cid].push(w);

console.log('Accumulated:', sd.res[cid].length, '/', w.total_works);

return { json: w };

// ═══════════════════════════════════════════════════════════════════════════
// UPDATE RESULT - Format result message (✓ Found / Not found)
// ═══════════════════════════════════════════════════════════════════════════

const calcData = $input.first().json;
const sd = $getWorkflowStaticData('global');
const cid = String(calcData.chatId);
const L = calcData.L || {};

const current = calcData.work_index || 1;
const total = calcData.total_works || 1;
const name = calcData.name || calcData.sq || 'Work';

let shortName = name.length > 22 ? name.substring(0, 19) + '...' : name;

const tc = parseFloat(calcData.tc) || 0;
const uc = parseFloat(calcData.uc) || 0;
const rateCode = String(calcData.rate_code || '');
const rateName = String(calcData.rate_name || '');
const currency = calcData.currency || L.sym || '€';

const hasValidRate = rateCode && 
  !rateCode.includes('NOT_FOUND') && 
  !rateCode.includes('PAYLOAD_NOT_FOUND');

const found = tc > 0 || uc > 0 || hasValidRate || (rateName && rateName.length > 0);

console.log('Result:', shortName, found ? '✓' : '✗', tc.toFixed(0), currency);

let text = '';
if (found) {
  text = current + '/' + total + ' ' + shortName + ' ✓\n';
  text += tc.toFixed(0) + ' ' + currency;
  if (rateCode && hasValidRate) text += ' · ' + rateCode.substring(0, 20);
} else {
  text = current + '/' + total + ' ' + shortName + '\n';
  text += (L.not_found || 'Не найдено');
}

const msgId = sd.calcProgress?.[cid]?.lastMsgId || null;

return { json: { ...calcData, _result_text: text, _edit_msg_id: msgId, _found: found } };

// ═══════════════════════════════════════════════════════════════════════════
// PREP QUERY - Prepare search query with credentials from TOKEN
// ═══════════════════════════════════════════════════════════════════════════

const loopItem = $input.first().json;
const tokenData = $('🔑 TOKEN').first().json;

const originalQuery = loopItem.sq || loopItem.query || loopItem.name || '';
const collectionName = loopItem.db || '';
const L = loopItem.L || {};
const workUnit = loopItem.unit || 'm²';
const workQty = loopItem.qty || 1;

// Get credentials from TOKEN node
const OPENAI_API_KEY = tokenData.OPENAI_API_KEY || '';
const QDRANT_URL = tokenData.QDRANT_URL || 'http://localhost:6333';
const QDRANT_API_KEY = tokenData.QDRANT_API_KEY || '';

console.log('=== PREP QUERY ===');
console.log('Query:', originalQuery);
console.log('Collection:', collectionName);
console.log('Qdrant URL:', QDRANT_URL);

if (!OPENAI_API_KEY || !originalQuery || !collectionName) {
  console.log('ERROR: Missing required data');
  return [{ json: { ...loopItem, _error: 'Missing data', _skip: true } }];
}

const searchLang = L.search_lang || 'Russian';

// Detect database language from collection name
const isRussianDB = collectionName.includes('RU_') || collectionName.includes('_RU');
const isGermanDB = collectionName.includes('DE_');
const dbLang = isRussianDB ? 'Russian' : (isGermanDB ? 'German' : 'English');

const transformPrompt = `You are a construction cost database search expert for ${dbLang} construction rates database.

TASK: Transform user query into optimal SEARCH KEYWORDS that will match entries in a vector database of construction work rates.

DATABASE CONTEXT:
- Contains standardized construction work rates with codes, names, units, resources
- Each rate has: rate_code, rate_name, rate_unit, scope_of_work, resources
- Language: ${dbLang}

TRANSFORMATION RULES:
1. EXPAND abbreviations to full professional terms
2. ADD synonyms and related construction terms
3. INCLUDE work action verbs (install, apply, lay, mount)
4. Keep original query terms + expanded terms
5. Output in ${dbLang} language only

USER QUERY: ${originalQuery}
UNIT: ${workUnit}

Reply with ONLY the optimized search keywords (one line, no explanations):`;

return [{ json: {
  ...loopItem,
  _original_query: originalQuery,
  _transform_prompt: transformPrompt,
  _collection: collectionName,
  _openai_key: OPENAI_API_KEY,
  _db_lang: dbLang,
  _qdrant_url: QDRANT_URL,
  _qdrant_key: QDRANT_API_KEY
}}];

// ═══════════════════════════════════════════════════════════════════════════
// SAVE WORK MSG - Store message ID for later editing/deletion
// ═══════════════════════════════════════════════════════════════════════════

const loopItem = $('📝 Prep Work Msg').first().json;
const tgResp = $input.first().json;
const sd = $getWorkflowStaticData('global');
const cid = String(loopItem.chatId);

if (!sd.calcProgress) sd.calcProgress = {};
if (!sd.calcProgress[cid]) sd.calcProgress[cid] = {};
sd.calcProgress[cid].lastMsgId = tgResp.result?.message_id || null;

console.log('Saved msg ID:', sd.calcProgress[cid].lastMsgId);

return { json: loopItem };

// ═══════════════════════════════════════════════════════════════════════════
// PREP WORK MSG - Create "Searching..." message for current work
// ═══════════════════════════════════════════════════════════════════════════

const loopItem = $('Loop').first().json;
const sd = $getWorkflowStaticData('global');
const cid = String(loopItem.chatId);
const L = loopItem.L || {};

const current = loopItem.work_index || 1;
const total = loopItem.total_works || 1;
const name = loopItem.name || loopItem.sq || 'Work';
const qty = loopItem.qty || 1;
const unit = loopItem.unit || 'm²';
const room = loopItem.room || '';

let shortName = name.length > 25 ? name.substring(0, 22) + '...' : name;

// Minimal message
let text = current + '/' + total + ' ' + shortName + '\n';
text += qty + ' ' + unit;
if (room) text += ' · ' + room;
text += '\n...';

const prevMsgId = sd.calcProgress?.[cid]?.lastMsgId || null;

console.log('Work', current, '/', total);

return { json: { ...loopItem, _work_text: text, _prev_msg_id: prevMsgId } };

// ═══════════════════════════════════════════════════════════════════════════
// PREP WORKS - Prepare work items for calculation loop (FREE DEMO: 5 items)
// ═══════════════════════════════════════════════════════════════════════════

const cfg = $input.first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');
const session = sd.sess?.[cid] || {};

// Get limited works list (max 5 for FREE DEMO)
const FREE_LIMIT = cfg._free_limit || 5;
const works = session.limitedWorks || (session.works || []).slice(0, FREE_LIMIT);
const db = session.db || cfg.db;
const L = session.L || cfg.L;

// Initialize results accumulator
if (!sd.res) sd.res = {};
sd.res[cid] = [];

const totalWorks = works.length;

console.log('=== PREP WORKS ===');
console.log('Processing:', totalWorks, 'items');

// Return array for loop processing
return works.map((w, idx) => ({ 
  json: { 
    ...w, 
    db, 
    L, 
    currency: L?.sym || '€',
    bot_token: cfg.bot_token, 
    chatId: cid, 
    sq: w.query || w.name,
    original_query: w.query || w.name,
    work_index: idx + 1, 
    total_works: totalWorks,
    _is_limited: cfg._is_limited,
    _original_total: cfg._total_works
  } 
}));

// ═══════════════════════════════════════════════════════════════════════════
// SAVE PROGRESS ID - Store initial progress message ID for cleanup
// ═══════════════════════════════════════════════════════════════════════════

const cfg = $('Config').first().json;
const prepData = $('📝 Prep Progress').first().json;
const telegramResponse = $input.first().json;
const sd = $getWorkflowStaticData('global');
const cid = String(cfg.chatId);

// Store progress message info
if (!sd.progress) sd.progress = {};
sd.progress[cid] = {
  message_id: telegramResponse.result?.message_id || 0,
  chat_id: cfg.chatId,
  bot_token: cfg.bot_token
};

// Initialize calculation progress tracker
if (!sd.calcProgress) sd.calcProgress = {};
sd.calcProgress[cid] = { lastMsgId: null };

console.log('Progress msg ID:', sd.progress[cid].message_id);

return { 
  json: { 
    ...cfg,
    _free_limit: prepData._free_limit,
    _is_limited: prepData._is_limited,
    _total_works: prepData._total_works
  } 
};

// ═══════════════════════════════════════════════════════════════════════════
// PREP PROGRESS - Show initial calculation message with FREE DEMO limit
// ═══════════════════════════════════════════════════════════════════════════

const cfg = $('Config').first().json;
const sd = $getWorkflowStaticData('global');
const cid = String(cfg.chatId);
const session = sd.sess?.[cid] || {};

const allWorks = session.works || [];

// Get L from Config (primary) or session (fallback)
const L = cfg.L || session.L || {};

console.log('=== PREP PROGRESS ===');
console.log('L.search_lang:', L.search_lang);

// FREE DEMO LIMIT
const FREE_LIMIT = 5;
const totalWorks = allWorks.length;
const isLimited = totalWorks > FREE_LIMIT;
const worksToProcess = Math.min(totalWorks, FREE_LIMIT);

session.isLimited = isLimited;
session.totalWorks = totalWorks;
session.limitedWorks = allWorks.slice(0, FREE_LIMIT);

const estimatedMinutes = Math.max(1, Math.ceil(worksToProcess * 8 / 60));

// Use localized text with Russian fallback
const calcWord = L.loading || 'Расчёт...';
const itemsWord = L.items || 'позиций';
const minWord = L.min || 'мин';

let text = '';
if (isLimited) {
  text = 'FREE DEMO · ' + FREE_LIMIT + '/' + totalWorks + ' ' + itemsWord + '\n';
} else {
  text = calcWord + ' ' + worksToProcess + ' ' + itemsWord + '\n';
}
text += '~' + estimatedMinutes + ' ' + minWord;

return {
  json: {
    ...cfg,
    _progress_chat_id: cfg.chatId,
    _progress_text: text,
    _free_limit: FREE_LIMIT,
    _is_limited: isLimited,
    _total_works: totalWorks
  }
};

// 📄 PDF DOWNLOAD PREP
const cfg = $('Config').first().json;
console.log('=== PDF DOWNLOAD PREP ===');
return {
  json: {
    ...cfg,
    pdfFileId: cfg.pdfFileId,
    pdfFileName: cfg.pdfFileName || 'document.pdf'
  }
};

// 🧹 DEDUPLICATE & MERGE v7
const cfgNode = $('Config').first().json;
const cid = String(cfgNode.chatId);
const sd = $getWorkflowStaticData('global');
const acc = sd.pdfAcc?.[cid] || { rooms: [], works: [] };

console.log('=== DEDUPLICATE v7 ===');
console.log('Raw rooms:', acc.rooms.length, 'works:', acc.works.length);

// Dedupe rooms
const roomMap = new Map();
for (const r of acc.rooms) {
  const key = (r.name || '').toLowerCase().trim();
  if (!roomMap.has(key) || (r.area_m2 || 0) > (roomMap.get(key).area_m2 || 0)) {
    roomMap.set(key, r);
  }
}
const rooms = Array.from(roomMap.values()).map((r, i) => ({
  ...r,
  id: 'R' + String(i + 1).padStart(3, '0')
}));

// Dedupe works
const workMap = new Map();
for (const w of acc.works) {
  const key = (w.name || '').toLowerCase().trim() + '_' + (w.unit || '') + '_' + (w.room || '');
  if (workMap.has(key)) {
    workMap.get(key).qty += (w.qty || 1);
  } else {
    workMap.set(key, { ...w, qty: w.qty || 1 });
  }
}

const works = Array.from(workMap.values()).map((w, i) => ({
  id: 'W' + String(i + 1).padStart(3, '0'),
  seq: i + 1,
  name: w.name,
  query: w.query || w.name,
  qty: Math.round((w.qty || 1) * 100) / 100,
  unit: w.unit || 'm²',
  room: w.room || '',
  details: w.details || '',
  conf: 'medium'
}));

console.log('Unique rooms:', rooms.length, 'works:', works.length);

const totalArea = rooms.reduce((sum, r) => sum + (r.area_m2 || 0), 0);

// Save to session
if (!sd.sess) sd.sess = {};
if (!sd.sess[cid]) sd.sess[cid] = {};
sd.sess[cid].works = works;
sd.sess[cid].rooms = rooms;
sd.sess[cid].totalArea = totalArea;
sd.sess[cid].L = cfgNode.L;
sd.sess[cid].state = 'wait_edit';

// Cleanup
if (sd.pdfAcc) delete sd.pdfAcc[cid];
if (sd.pdfData) delete sd.pdfData[cid];

return {
  json: {
    chatId: cfgNode.chatId,
    bot_token: cfgNode.bot_token,
    L: cfgNode.L,
    works,
    rooms,
    totalArea
  }
};

// ═══════════════════════════════════════════════════════════════════════════
// SHOW WORKS - Display extracted work items with edit buttons
// ═══════════════════════════════════════════════════════════════════════════

const cfgNode = $('Config').first().json;
const inputData = $input.first().json;
const sd = $getWorkflowStaticData('global');

const chatId = inputData.chatId || cfgNode.chatId;
const bot_token = inputData.bot_token || cfgNode.bot_token;
const cid = String(chatId);

// Get L from multiple sources (session is most reliable)
const session = sd.sess?.[cid] || {};
let L = cfgNode.L || session.L || inputData.L || {};

// Get works from input (from Deduplicate) or session
const works = inputData.works || session.works || [];
const rooms = inputData.rooms || session.rooms || [];

console.log('=== SHOW WORKS ===');
console.log('Works:', works.length);
console.log('L.search_lang:', L.search_lang);

// Save to session
if (!sd.sess) sd.sess = {};
if (!sd.sess[cid]) sd.sess[cid] = {};
if (works.length > 0) {
  sd.sess[cid].works = works;
  sd.sess[cid].rooms = rooms;
  sd.sess[cid].L = L;
  sd.sess[cid].db = cfgNode.db;
  sd.sess[cid].state = 'wait_edit';
}

function short(str, len) {
  str = String(str || '');
  return str.length > len ? str.substring(0, len - 1) + '…' : str;
}

const totalArea = rooms.reduce((sum, r) => sum + (r.area_m2 || 0), 0);

// Use localized labels with fallback
const roomWord = L.rooms || 'комнат';
const workWord = L.works_identified || 'позиций';
const generalWord = L.general || 'Общее';

let msg = '*' + rooms.length + ' ' + roomWord;
if (totalArea > 0) msg += ' · ' + (Math.round(totalArea * 10) / 10) + ' m²';
msg += '*\n';
msg += '_' + works.length + ' ' + workWord + '_\n\n';

if (works.length === 0) {
  msg += '_' + (L.no_works || 'Работы не найдены') + '_\n';
} else {
  const worksByRoom = new Map();
  const noRoom = [];

  for (const w of works) {
    if (w.room && w.room.length > 0) {
      if (!worksByRoom.has(w.room)) worksByRoom.set(w.room, []);
      worksByRoom.get(w.room).push(w);
    } else {
      noRoom.push(w);
    }
  }

  let workNum = 1;

  for (const [roomName, roomWorks] of worksByRoom) {
    const room = rooms.find(r => r.name === roomName);
    const areaStr = room?.area_m2 ? ' · ' + room.area_m2 + ' m²' : '';
    msg += '*' + short(roomName, 20) + '*' + areaStr + '\n';

    for (const w of roomWorks) {
      const wname = short(w.name || 'Work', 25);
      const qty = typeof w.qty === 'number' ? Math.round(w.qty * 100) / 100 : w.qty;
      msg += workNum + '. ' + wname + ' — ' + qty + ' ' + (w.unit || '') + '\n';
      workNum++;
    }
    msg += '\n';
  }

  if (noRoom.length > 0) {
    msg += '*' + generalWord + '*\n';
    for (const w of noRoom) {
      const wname = short(w.name || 'Work', 25);
      const qty = typeof w.qty === 'number' ? Math.round(w.qty * 100) / 100 : w.qty;
      msg += workNum + '. ' + wname + ' — ' + qty + ' ' + (w.unit || '') + '\n';
      workNum++;
    }
  }
}

// Build keyboard
const keyboard = [];
const maxBtns = works.length;
if (maxBtns > 0) {
  for (let i = 0; i < maxBtns; i += 5) {
    const row = [];
    for (let j = 0; j < 5 && i + j < maxBtns; j++) {
      row.push({ text: '✏' + (i + j + 1), callback_data: 'edit_work_' + (i + j) });
    }
    keyboard.push(row);
  }
}

keyboard.push([
  { text: L.btn_add_work || '+ Позиция', callback_data: 'add_work' },
  { text: L.btn_calc || '▶ Расчёт', callback_data: 'calculate' }
]);
keyboard.push([
  { text: L.btn_new || '🔄 Заново', callback_data: 'new_photo' }
]);

return { json: { chatId, bot_token, L, msg, keyboard, works, rooms } };

// 📦 ACCUMULATE v7
const cfg = $input.first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');

if (!sd.pdfAcc) sd.pdfAcc = {};
if (!sd.pdfAcc[cid]) sd.pdfAcc[cid] = { rooms: [], works: [], totalArea: 0 };

const acc = sd.pdfAcc[cid];

if (cfg.pageRooms) acc.rooms.push(...cfg.pageRooms);
if (cfg.pageWorks) acc.works.push(...cfg.pageWorks);
if (cfg.totalArea) acc.totalArea = Math.max(acc.totalArea, cfg.totalArea);

console.log('Accumulated - rooms:', acc.rooms.length, 'works:', acc.works.length);

return { json: { ...cfg } };

// 🏠 PARSE PDF PAGE v7
const prepData = $('👁️ Prep Vision PDF').first().json;
const resp = $input.first().json;

if (prepData._skip_vision) {
  return { json: { ...prepData, pageRooms: [], pageWorks: [], totalArea: 0 } };
}

let raw = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
let parsed = { rooms: [], works: [], total_area_m2: 0 };

try {
  let clean = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
  const s = clean.indexOf('{'), e = clean.lastIndexOf('}');
  if (s !== -1 && e > s) {
    parsed = JSON.parse(clean.substring(s, e + 1));
  }
  console.log('Parsed - rooms:', parsed.rooms?.length, 'works:', parsed.works?.length);
} catch(err) {
  console.log('Parse error:', err.message);
}

const rooms = (parsed.rooms || []).map((r, i) => ({
  id: 'R' + String(i + 1).padStart(3, '0'),
  name: r.name || 'Room ' + (i + 1),
  area_m2: r.area_m2 || 0
}));

const works = (parsed.works || []).map((w, i) => {
  let name = w.name || 'Work';
  if (w.details && w.details.length > 0 && w.details.length < 30) {
    name = name + ' ' + w.details;
  }
  return {
    id: 'W' + String(i + 1).padStart(3, '0'),
    name: name.trim(),
    query: (w.name || 'Work').trim(),
    room: w.room || '',
    qty: w.qty || w.quantity || 1,
    unit: w.unit || 'm²',
    details: w.details || '',
    conf: 'medium'
  };
});

return {
  json: {
    ...prepData,
    pageRooms: rooms,
    pageWorks: works,
    totalArea: parsed.total_area_m2 || 0
  }
};

// 👁️ PREP VISION PDF v7 - UNIVERSAL
const cfgNode = $('Config').first().json;
