parameters.jsCode:
// ═══════════════════════════════════════════════════════════════════════════
// 6️⃣ PREP RERANK v4 - Enhanced semantic matching
// ═══════════════════════════════════════════════════════════════════════════

const prepData = $('4️⃣ Extract Embedding').first().json;
const qdrantResponse = $input.first().json;

console.log('=== PREP RERANK v4 ===');

if (qdrantResponse.status?.error) {
  return [{ json: { ...prepData, rate_code: 'QDRANT_ERROR', uc: 0, tc: 0, ql: 'not_found', resources: [] }}];
}

const results = qdrantResponse.result || [];
console.log('Qdrant results:', results.length);

if (results.length === 0) {
  return [{ json: { ...prepData, rate_code: 'NOT_FOUND', rate_name: prepData._original_query, uc: 0, tc: 0, ql: 'not_found', resources: [] }}];
}

const originalQuery = prepData._original_query || prepData.name || '';
const workUnit = prepData.unit || 'm²';
const workQty = prepData.qty || 1;

// Format компактное описание кандидатов
const candidates = results.slice(0, 5).map((r, i) => {
  const p = r.payload || {};
  const code = p.rate_code || '';
  const name = p.rate_name || '';
  const unit = p.rate_unit || '';

  // Scope of work
  const workSteps = p.work_steps || [];
  const scopeText = workSteps.slice(0, 3).map(s => s.text).join('; ');

  // Key materials
  const resources = p.resources || [];
  const materials = resources
    .filter(r => !r.resource_code?.match(/^(DXME|ME_|PU_|RI_)/))
    .slice(0, 3)
    .map(r => r.resource_name)
    .join(', ');

  const qdrantScore = (r.score * 100).toFixed(0);

  console.log('[' + i + '] ' + code + ' - ' + name?.substring(0, 40) + ' | ' + qdrantScore + '%');

  return i + '. [' + code + '] ' + name + '\n   Unit: ' + unit + ' | Scope: ' + (scopeText || 'n/a').substring(0, 100) + '\n   Materials: ' + (materials || 'n/a');
}).join('\n\n');

const rerankPrompt = `TASK: Score construction rate candidates (0-100) for matching user's work request.

SCORING GUIDE:
95-100: EXACT MATCH - Same work type, method, materials, unit compatible
80-94: VERY GOOD - Same work, minor spec differences (thickness, brand)
65-79: GOOD - Same category, different specification
50-64: PARTIAL - Related work, different scope
30-49: WEAK - Same trade, different work type
0-29: WRONG - Different trade or unrelated

CRITICAL DISTINCTIONS:
• ГКЛ (гипсокартон) ≠ ГВЛ (гипсоволокно) - DIFFERENT materials, max 60
• Стены ≠ Потолок - check work location matches
• Монтаж ≠ Демонтаж - opposite operations
• 1 слой ≠ 2 слоя - check layer count
• Profile types: ПП60 = ceiling, ПС = wall stud, ПН = guide

UNIT MATCHING:
• Query unit: ${workUnit}
• Rate unit should be compatible or convertible
• m² work → m² rate (ideal)
• m² work → 100m² rate (ok, will scale)

USER REQUEST: "${originalQuery}" (${workQty} ${workUnit})

CANDIDATES:
${candidates}

Return ONLY valid JSON (no markdown):
{"rankings":[{"index":0,"score":N,"reason":"brief reason"},{"index":1,"score":N,"reason":"brief reason"}]}`;

console.log('Prompt length:', rerankPrompt.length);

return [{ json: {
  ...prepData,
  _qdrant_results: results,
  _rerank_prompt: rerankPrompt,
  _openai_key: prepData._openai_key,
  _step: 'prep_rerank_done'
}}];

// ═══════════════════════════════════════════════════════════════════════════
// EXTRACT EMBEDDING - Get vector from OpenAI response
// ═══════════════════════════════════════════════════════════════════════════

const prepData = $('2️⃣ Extract Transform').first().json;
const embResponse = $input.first().json;

console.log('=== EXTRACT EMBEDDING ===');

if (embResponse.error) {
  console.log('OpenAI Error:', embResponse.error.message);
  return [{ json: { ...prepData, _error: embResponse.error.message, _embedding: [] }}];
}

const embedding = embResponse.data?.[0]?.embedding || [];
console.log('Embedding length:', embedding.length);

if (embedding.length !== 3072) {
  console.log('WARNING: Expected 3072, got', embedding.length);
}

// Pass all data including Qdrant credentials
return [{ json: {
  ...prepData,
  _embedding: embedding,
  _collection: prepData._collection,
  _qdrant_url: prepData._qdrant_url,
  _qdrant_key: prepData._qdrant_key,
  _openai_key: prepData._openai_key,
  _step: 'embedding_done'
}}];

// ═══════════════════════════════════════════════════════════════════════════
// EXTRACT TRANSFORM - Clean LLM response and combine queries
// ═══════════════════════════════════════════════════════════════════════════

const prepData = $('1️⃣ Prep Query').first().json;
const llmResponse = $input.first().json;

console.log('=== EXTRACT TRANSFORM ===');

let transformedQuery = prepData._original_query;

try {
  const content = llmResponse.choices?.[0]?.message?.content || '';
  if (content && content.length > 5) {
    transformedQuery = content
      .replace(/^(keywords?:|search:|query:|result:)/i, '')
      .replace(/[\n\r]+/g, ' ')
      .trim();
    console.log('Transformed OK');
  }
} catch(e) {
  console.log('Transform failed:', e.message);
}

console.log('Original:', prepData._original_query);
console.log('Transformed:', transformedQuery.substring(0, 80));

// Smart combination - original is more important
const originalWords = prepData._original_query.toLowerCase().split(/\s+/);
const transformedWords = transformedQuery.toLowerCase().split(/\s+/);

// Add only new words from transformation
const newWords = transformedWords.filter(w => 
  w.length > 2 && !originalWords.some(ow => ow.includes(w) || w.includes(ow))
);

const combinedQuery = prepData._original_query + ' ' + newWords.slice(0, 10).join(' ');

console.log('Combined:', combinedQuery.substring(0, 100));

// Pass all data including Qdrant credentials
return [{ json: {
  ...prepData,
  _query: combinedQuery.trim(),
  _transformed_query: transformedQuery,
  _collection: prepData._collection,
  _qdrant_url: prepData._qdrant_url,
  _qdrant_key: prepData._qdrant_key,
  _openai_key: prepData._openai_key,
  _step: 'transform_done'
}}];

// ═══════════════════════════════════════════════════════════════════════════
// DDC CWICR - Parse Text LLM Response
// Extract works from LLM API response
// ═══════════════════════════════════════════════════════════════════════════

const prepData = $('Prep Text LLM').first().json;
const apiResponse = $input.first().json;
const cid = String(prepData.chatId);
const sd = $getWorkflowStaticData('global');
const L = prepData.L || {};
const provider = prepData._llm_provider || 'gemini';

console.log('=== PARSE TEXT LLM ===');
console.log('Provider:', provider);

let works = [];
let rawContent = '';

try {
  // Extract text based on provider
  if (provider === 'openai') {
    rawContent = apiResponse.choices?.[0]?.message?.content || '';
  } else {
    rawContent = apiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
  }

  console.log('Raw response length:', rawContent.length);
  console.log('Raw response preview:', rawContent.substring(0, 200));

  if (rawContent) {
    // Clean and parse JSON
    let cleanContent = rawContent
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/gi, '')
      .replace(/^[^\[]*/, '')  // Remove anything before [
      .trim();

    const jsonStart = cleanContent.indexOf('[');
    const jsonEnd = cleanContent.lastIndexOf(']');

    if (jsonStart !== -1 && jsonEnd !== -1) {
      const jsonStr = cleanContent.substring(jsonStart, jsonEnd + 1);
      console.log('JSON to parse:', jsonStr.substring(0, 200));
      works = JSON.parse(jsonStr);
      console.log('Parsed works count:', works.length);
    }
  }
} catch(e) {
  console.log('Parse error:', e.message);
}

// Validate and normalize
const validWorks = (works || [])
  .filter(w => w && w.name && String(w.name).length > 2)
  .map((w, i) => ({
    id: 'W' + String(i + 1).padStart(3, '0'),
    seq: i + 1,
    name: String(w.name).substring(0, 80).trim(),
    query: String(w.name).substring(0, 80).trim(),
    qty: Math.max(0.1, parseFloat(w.qty) || 1),
    unit: ['m²', 'm', 'pcs', 'kg', 'l', 'шт', 'м²', 'м', 'St', 'Stk'].includes(w.unit) ? w.unit : 'm²',
    room: w.room || '',
    conf: 'medium',
    cat: 'finishing'
  }));

console.log('Valid works:', validWorks.length);

// Save to session
if (!sd.sess) sd.sess = {};
if (!sd.sess[cid]) sd.sess[cid] = { lang: prepData.lang };
sd.sess[cid].works = validWorks;
sd.sess[cid].description = prepData.description || '';
sd.sess[cid].state = 'wait_edit';
sd.sess[cid].db = prepData.db;
sd.sess[cid].L = L;

return { json: { 
  ...prepData,
  chatId: cid, 
  works: validWorks,
  description: prepData.description || '',
  L
}};

// ═══════════════════════════════════════════════════════════════════════════
// DDC CWICR - Data Driven Construction Cost Estimator
// https://DataDrivenConstruction.io
// Open source construction cost database with 55,000+ work items
// ═══════════════════════════════════════════════════════════════════════════

// Detailed view with resource prices
const cfg = $('Config').first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');
const data = sd.lastResults || {};
const L = data.L || cfg.L || {};
const works = data.works || [];
const sym = L.sym || '€';

function fmtCur(v) { 
  if (!v || v === 0) return sym + ' 0';
  return sym + ' ' + v.toFixed(2); 
}

let msg = `*${L.ready} — ${L.resources}*\n\n`;

works.forEach((w, i) => {
  const qi = { 'high': '●', 'medium': '○', 'low': '◌', 'not_found': '✕' }[w.ql] || '○';

  msg += `*${i+1}. ${w.name}*\n`;
  if (w.rate_code && w.rate_code !== 'NOT_FOUND') {
    msg += `${qi} \`${w.rate_code}\`\n`;
    if (w.rate_name && w.rate_name !== w.name) {
      const rateName = (w.rate_name || '').substring(0, 45);
      msg += `_${rateName}_\n`;
    }
  } else {
    msg += `${qi} _${L.not_found}_\n`;
  }
  msg += `${w.qty} ${w.unit} × ${fmtCur(w.uc)} = *${fmtCur(w.tc)}*\n`;

  // Cost breakdown
  const parts = [];
  if (w.workers_total > 0) parts.push(`${L.workers}: ${fmtCur(w.workers_total)}`);
  if (w.materials_total > 0) parts.push(`${L.materials}: ${fmtCur(w.materials_total)}`);
  if (w.machines_total > 0) parts.push(`${L.machines}: ${fmtCur(w.machines_total)}`);
  if (parts.length > 0) msg += `_${parts.join(' · ')}_\n`;

  // Resources with prices
  const resources = w.resources || [];
  if (resources.length > 0) {
    msg += `\n`;
    const showCount = Math.min(5, resources.length);
    resources.slice(0, showCount).forEach((r, ri) => {
      const isLast = ri === showCount - 1 && resources.length <= 5;
      const prefix = isLast ? '└' : '├';
      const typeTag = r.resource_type === 'labor' ? L.res_labor : r.resource_type === 'machine' ? L.res_machine : L.res_material;
      const resName = (r.resource_name || '').substring(0, 26);
      msg += `${prefix} *${typeTag}*: ${resName}\n`;

      // Show quantity and cost
      const qtyVal = r.scaled_quantity || r.resource_quantity || 0;
      const costVal = r.scaled_cost || r.resource_cost || 0;
      if (costVal > 0) {
        msg += `   ${qtyVal.toFixed(2)} ${r.resource_unit || ''} = ${fmtCur(costVal)}\n`;
      } else {
        msg += `   ${qtyVal.toFixed(2)} ${r.resource_unit || ''}\n`;
      }
    });
    if (resources.length > 5) {
      msg += `└ _...+${resources.length - 5} ${L.resources}_\n`;
    }
  }

  // Scope of work
  const scope = w.scope_of_work || [];
  if (scope.length > 0) {
    msg += `\n📋 *${L.scope_title || 'Scope of Work'}:*\n`;
    scope.forEach((s, si) => {
      const prefix = si === scope.length - 1 ? '└' : '├';
      const sText = (s || '').substring(0, 45);
      msg += `${prefix} ${sText}\n`;
    });
  }
  msg += `\n`;
});

// Summary
msg += `─────────────────────\n`;
const totalParts = [];
if (data.workers_sum > 0) totalParts.push(`${L.workers}: ${fmtCur(data.workers_sum)}`);
if (data.materials_sum > 0) totalParts.push(`${L.materials}: ${fmtCur(data.materials_sum)}`);
if (data.machines_sum > 0) totalParts.push(`${L.machines}: ${fmtCur(data.machines_sum)}`);
if (totalParts.length > 0) msg += totalParts.join('\n') + '\n\n';

msg += `*${L.total}: ${fmtCur(data.total || 0)}*\n`;

return { json: { ...cfg, msg, chatId: cid, bot_token: cfg.bot_token, L } };

// ═══════════════════════════════════════════════════════════════════════════
// DDC CWICR - Data Driven Construction Cost Estimator
// https://DataDrivenConstruction.io
// Open source construction cost database with 55,000+ work items
// ═══════════════════════════════════════════════════════════════════════════

// Generate PDF (using HTML-to-PDF service or return HTML)
const cfg = $('Config').first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');
const html = sd.html_report || '';
const L = sd.lastResults?.L || cfg.L || {};

if (!html) {
  // No HTML report yet - send message
  try {
    await $http.request({
      method: 'POST',
      url: `https://api.telegram.org/bot${cfg.bot_token}/sendMessage`,
      body: { chat_id: parseInt(cid), text: '❌ No report to export. Please calculate first.' },
      json: true
    });
  } catch(e) {}
  return { json: { skip: true } };
}

// For now, send HTML file as "PDF alternative"
const filename = `Estimate_${(L.region || 'Report').replace(/[^a-zA-Z0-9]/g, '_')}_${new Date().toISOString().substring(0, 10)}.html`;

return { json: { chatId: cid, L, bot_token: cfg.bot_token, filename }, binary: { pdf: { data: Buffer.from(html, 'utf-8').toString('base64'), mimeType: 'text/html', fileName: filename } } };

// ═══════════════════════════════════════════════════════════════════════════
// DDC CWICR - Data Driven Construction Cost Estimator
// https://DataDrivenConstruction.io
// Open source construction cost database with 55,000+ work items
// ═══════════════════════════════════════════════════════════════════════════

// Generate Excel file
const cfg = $('Config').first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');
const data = sd.lastResults || {};
const L = data.L || cfg.L || {};
const works = data.works || [];

// Create CSV content (Excel-compatible)
let csv = '\uFEFF'; // BOM for UTF-8
csv += `${L.doc_title || 'ESTIMATE'} - ${data.description || 'Photo Estimate'}\n`;
csv += `${L.region || 'Region'} | ${new Date().toLocaleDateString()}\n\n`;

// Headers
csv += `${L.col_pos || 'Pos'};${L.col_code || 'Code'};${L.col_desc || 'Description'};${L.col_unit || 'Unit'};${L.col_qty || 'Qty'};${L.col_price || 'Price'};${L.col_total || 'Total'}\n`;

// Data rows
works.forEach((w, i) => {
  const name = (w.rate_name || w.name || '').replace(/;/g, ',').replace(/\n/g, ' ');
  csv += `${i+1};${w.rate_code || ''};"${name}";${w.rate_unit || w.unit || ''};${(w.qty || 0).toFixed(2)};${(w.uc || 0).toFixed(2)};${(w.tc || 0).toFixed(2)}\n`;

  // Resources
  (w.resources || []).forEach(r => {
    const resName = (r.resource_name || '').replace(/;/g, ',').replace(/\n/g, ' ');
    csv += `;${r.resource_code || ''};"  ${resName}";${r.resource_unit || ''};${(r.scaled_quantity || 0).toFixed(3)};${(r.resource_price || 0).toFixed(2)};${(r.scaled_cost || 0).toFixed(2)}\n`;
  });
});

// Totals
csv += `\n;;;;;${L.total || 'TOTAL'};${(data.total || 0).toFixed(2)}\n`;
csv += `;;;;;${L.workers || 'Labor'};${(data.workers_sum || 0).toFixed(2)}\n`;
csv += `;;;;;${L.materials || 'Materials'};${(data.materials_sum || 0).toFixed(2)}\n`;
csv += `;;;;;${L.machines || 'Equipment'};${(data.machines_sum || 0).toFixed(2)}\n`;

const filename = `Estimate_${(L.region || 'Report').replace(/[^a-zA-Z0-9]/g, '_')}_${new Date().toISOString().substring(0, 10)}.csv`;

return { json: { chatId: cid, L, bot_token: cfg.bot_token, filename }, binary: { excel: { data: Buffer.from(csv, 'utf-8').toString('base64'), mimeType: 'text/csv', fileName: filename } } };

