// DDC CWICR - Final message with resources preview
// ═══════════════════════════════════════════════════════════════════════════

const d = $('Generate HTML').first().json;
const cid = d.chatId;
const sd = $getWorkflowStaticData('global');
const L = d.L || {};

if (sd.res?.[cid]) delete sd.res[cid];
if (sd.sess?.[cid]) sd.sess[cid].state = 'done';

function fmt(v) { 
  try { return new Intl.NumberFormat(L.loc || 'en', { maximumFractionDigits: 0 }).format(v || 0); } 
  catch(e) { return (v || 0).toFixed(0); } 
}
function fmtCur(v) { 
  const sym = L.sym || '$';
  if (Math.abs(v) >= 1000) return sym + ' ' + fmt(v);
  return sym + ' ' + (v || 0).toFixed(2);
}
function shortName(str, len) {
  str = String(str || '');
  if (str.length > len) return str.substring(0, len - 1) + '...';
  return str;
}

function escMd(s) {
  // Remove Markdown special chars for Telegram (Markdown mode doesn't support escaping)
  return String(s || '').replace(/[_*`\[\]]/g, '');
}

const works = d.works || [];
const total = d.total || 0;
const now = new Date();
const dateStr = now.toLocaleDateString(L.loc || 'en', { year: 'numeric', month: '2-digit', day: '2-digit' });

const qiMarks = { 'high': '●', 'medium': '○', 'low': '◌', 'not_found': '✕' };

// Header
let msg = `*${L.doc_title || 'COST ESTIMATE'}*\n`;
msg += `${dateStr} · ${L.region || ''}\n\n`;

// Works with resources
works.forEach((w, i) => {
  const qi = qiMarks[w.ql] || '○';
  const name = escMd(shortName(w.rate_name || w.name || '', 30));
  const sumStr = fmtCur(w.tc);

  msg += `${qi} *${i+1}.* ${name}\n`;
  msg += `   ${w.qty} ${w.unit} × ${fmtCur(w.uc)} = *${sumStr}*\n`;

  // Show 2-3 resources
  const resources = w.resources || [];
  if (resources.length > 0) {
    const preview = resources.slice(0, 3);
    preview.forEach((r, ri) => {
      const isLast = ri === preview.length - 1 && resources.length <= 3;
      const prefix = isLast ? '└' : '├';
      const typeIcon = r.resource_type === 'labor' ? 'L' : r.resource_type === 'machine' ? 'M' : 'R';
      const rName = escMd(shortName(r.resource_name || '', 40));
      const rCost = fmtCur(r.scaled_cost || 0);
      msg += `   ${prefix} [${typeIcon}] ${rName} ${rCost}\n`;
    });
    if (resources.length > 3) {
      msg += `   └ +${resources.length - 3} ${L.more_resources || 'more'}\n`;
    }
  }

  // Show scope of work preview
  const scope = w.scope_of_work || [];
  if (scope.length > 0) {
    msg += `   📋 ${L.scope_title || 'Scope'}:\n`;
    const scopePreview = scope.slice(0, 2);
    scopePreview.forEach((s, si) => {
      const isLast = si === scopePreview.length - 1 && scope.length <= 2;
      const prefix = isLast ? '   └' : '   ├';
      const sText = escMd(shortName(s, 35));
      msg += `${prefix} • ${sText}\n`;
    });
    if (scope.length > 2) {
      msg += `   └ +${scope.length - 2} ${L.more_resources || 'more'}\n`;
    }
  }
});

// Total
msg += `━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
msg += `*${L.total || 'TOTAL'}:* ${fmtCur(total)}\n\n`;

// Quality legend
const qHigh = works.filter(w => w.ql === 'high').length;
const qMed = works.filter(w => w.ql === 'medium').length;
const qLow = works.filter(w => w.ql === 'low').length;
const qNone = works.filter(w => w.ql === 'not_found').length;

const avgLLM = works.length > 0 ? Math.round(works.reduce((s, w) => s + (w.llm_score || 0), 0) / works.length) : 0;
msg += `● ${qHigh}  ○ ${qMed}  ◌ ${qLow}  ✕ ${qNone}  (${d.pct}% ${L.found_pct || 'found'})\n`;
if (avgLLM > 0) msg += `🎯 AI: ${avgLLM}%\n`;
msg += `\n`;

// Cost breakdown
if (d.workers_sum > 0 || d.materials_sum > 0 || d.machines_sum > 0) {
  const parts = [];
  if (d.workers_sum > 0) parts.push(`${L.workers || 'Labor'}: ${fmtCur(d.workers_sum)}`);
  if (d.materials_sum > 0) parts.push(`${L.materials || 'Mat'}: ${fmtCur(d.materials_sum)}`);
  if (d.machines_sum > 0) parts.push(`${L.machines || 'Equip'}: ${fmtCur(d.machines_sum)}`);
  msg += parts.join(' · ') + '\n';
}

if (d.labor_hours_sum > 0) {
  const days = Math.ceil(d.labor_hours_sum / 8);
  msg += `${L.labor_hours || 'Hours'}: ${fmt(d.labor_hours_sum)}h · ~${days} ${L.days || 'days'}\n`;
}

msg += `\n_${L.price_note || 'Prices are approximate'}_\n`;
msg += `_${L.more_in_html || 'Detailed report available'}_\n\n`;
msg += `${L.what_next || 'Options:'}`;

return { json: { ...d, msg } };

