<script>
function toggleWork(idx) {
  const icon = document.getElementById('icon-' + idx);
  const rows = document.querySelectorAll('tr[data-work="' + idx + '"]:not(.work-row)');
  const isHidden = rows.length > 0 && rows[0].classList.contains('hidden');
  rows.forEach(r => r.classList.toggle('hidden', !isHidden));
  if (icon) icon.textContent = isHidden ? '▼' : '▶';
}
function expandAll() {
  document.querySelectorAll('tr[data-work]').forEach(r => r.classList.remove('hidden'));
  document.querySelectorAll('[id^="icon-"]').forEach(i => i.textContent = '▼');
}
function collapseAll() {
  document.querySelectorAll('tr.res-row, tr.summary-row, tr.scope-row').forEach(r => r.classList.add('hidden'));
  document.querySelectorAll('[id^="icon-"]').forEach(i => i.textContent = '▶');
}
function toggleScope(idx) {
  const rows = document.querySelectorAll('tr.scope-row[data-scope="' + idx + '"]');
  rows.forEach(r => r.classList.toggle('hidden'));
}
</script>
