  for (let j = 0; j < 5 && i + j < maxBtns; j++) {
    row.push({ text: '✏️' + (i + j + 1), callback_data: 'edit_work_' + (i + j) });
  }
  keyboard.push(row);
}

keyboard.push([
  { text: L.btn_add_work || '+ Позиция', callback_data: 'add_work' },
  { text: L.btn_calc || '▶ Расчёт', callback_data: 'calculate' }
]);
keyboard.push([{ text: L.btn_new || '🔄 Заново', callback_data: 'new_photo' }]);

return { json: { ...cfg, msg, keyboard } };

// ═══════════════════════════════════════════════════════════════════════════
// PARSE AI RESPONSE - Extract work items from Vision API response
// ═══════════════════════════════════════════════════════════════════════════

const data = $input.first().json;
const cid = String(data.chatId);
const sd = $getWorkflowStaticData('global');
const L = data.L || {};
const provider = data.provider || 'gemini';

console.log('=== PARSE AI ===');
console.log('Provider:', provider);
console.log('ChatId:', cid);

let p = { description: '', items: [] };
let rawContent = '';

try {
  // Extract text from response based on provider
  if (provider === 'openai') {
    rawContent = data.choices?.[0]?.message?.content || '';
  } else {
    rawContent = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
  }

  console.log('Response length:', rawContent.length);

  if (rawContent) {
    // Clean markdown and extract JSON
    let cleanContent = rawContent
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/gi, '')
      .trim();

    const jsonStart = cleanContent.indexOf('{');
    const jsonEnd = cleanContent.lastIndexOf('}');

    if (jsonStart !== -1 && jsonEnd !== -1) {
      const jsonStr = cleanContent.substring(jsonStart, jsonEnd + 1);
      p = JSON.parse(jsonStr);
      console.log('Parsed items:', p.items?.length || 0);
    }
  }
} catch(e) { 
  console.log('Parse error:', e.message);
}

// Validate and normalize items
const validItems = (p.items || [])
  .filter(it => it.name && it.name.length > 2)
  .map((it, i) => ({
    id: 'W' + String(i + 1).padStart(3, '0'),
    seq: i + 1,
    name: String(it.name).substring(0, 80).trim(),
    query: String(it.name).substring(0, 80).trim(),
    qty: Math.max(0.1, parseFloat(it.qty) || 1),
    unit: ['m²', 'm', 'pcs', 'kg', 'l', 'шт', 'м²', 'м'].includes(it.unit) ? it.unit : 'm²',
    conf: ['high', 'medium', 'low'].includes(it.conf) ? it.conf : 'medium',
    cat: ['demolition', 'rough', 'finishing', 'mep'].includes(it.cat) ? it.cat : 'finishing'
  }));

console.log('Valid items:', validItems.length);

// ═══════════════════════════════════════════════════════════════════════════
// CRITICAL: Save works to session for later access
// ═══════════════════════════════════════════════════════════════════════════
if (!sd.sess) sd.sess = {};
if (!sd.sess[cid]) sd.sess[cid] = { lang: data.lang };

sd.sess[cid].works = validItems;
sd.sess[cid].description = p.description || '';
sd.sess[cid].state = 'wait_edit';
sd.sess[cid].db = data.db;
sd.sess[cid].L = data.L;

console.log('Saved to session:', sd.sess[cid].works.length, 'works');

return { 
  json: { 
    ...data,
    chatId: cid, 
    works: validItems,
    description: p.description || '',
    L: data.L
  }
};

