// ═══════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════
// MAIN ROUTER - Central message handler
// DDC CWICR - Data Driven Construction Cost Estimator
// https://DataDrivenConstruction.io
// ═══════════════════════════════════════════════════════════════════════════
// https://DataDrivenConstruction.io
// Open source construction cost database with 55,000+ work items
// ═══════════════════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════════════════
// MAIN ROUTER v8.5 PRO - Multi-photo, Voice, PDF, Edit, Categories, Export
// ═══════════════════════════════════════════════════════════════════════════

const update = $('Telegram Trigger').first().json;
const botToken = $input.first().json.bot_token;
const isCallback = !!update.callback_query;

let chatId, callbackData, callbackQueryId, text, fileId, hasImage, caption;
let hasVoice, voiceFileId, mediaGroupId;
let hasPDF, pdfFileId, pdfFileName; // PDF support

if (isCallback) {
  const cb = update.callback_query;
  chatId = cb.message?.chat?.id;
  callbackData = cb.data || '';
  callbackQueryId = cb.id;
  text = ''; fileId = null; hasImage = false; caption = ''; 
  hasVoice = false; voiceFileId = null; mediaGroupId = null;
  hasPDF = false; pdfFileId = null; pdfFileName = null;
} else {
  const msg = update.message || {};
  chatId = msg.chat?.id;
  callbackData = ''; callbackQueryId = '';
  text = msg.text || ''; caption = msg.caption || '';
  mediaGroupId = msg.media_group_id || null;

  // Photo detection
  const photo = msg.photo || [];
  fileId = photo.length > 0 ? photo[photo.length - 1].file_id : null;
  hasImage = !!fileId;
  if (!fileId && msg.document?.mime_type?.startsWith('image/')) {
    fileId = msg.document.file_id; hasImage = true;
  }

  // Voice detection
  hasVoice = !!(msg.voice || msg.audio);
  voiceFileId = msg.voice?.file_id || msg.audio?.file_id || null;

  // ═══════════════════════════════════════════════════════════════════════════
  // PDF DOCUMENT DETECTION
  // ═══════════════════════════════════════════════════════════════════════════
  const doc = msg.document || {};
  hasPDF = doc.mime_type === 'application/pdf';
  pdfFileId = hasPDF ? doc.file_id : null;
  pdfFileName = hasPDF ? (doc.file_name || 'document.pdf') : null;
}

const sd = $getWorkflowStaticData('global');
if (!sd.sess) sd.sess = {};
const cid = String(chatId);
if (!sd.sess[cid]) sd.sess[cid] = { 
  lang: null, works: [], state: 'new', db: null, L: null, 
  photos: [], voiceText: '', description: '',
  categories: { demolition: true, rough: true, finishing: true, mep: true },
  // PDF state
  pdfFileId: null, pdfFileName: null, pdfPages: [], 
  rooms: [], elements: [], pdfProcessed: false
};
const S = sd.sess[cid];

let action = 'none';

// === COMMANDS ===
if (text.toLowerCase() === '/start') {
  S.lang = null; S.works = []; S.state = 'wait_lang'; S.db = null; S.L = null;
  S.photos = []; S.voiceText = ''; S.description = '';
  S.pdfFileId = null; S.pdfFileName = null; S.rooms = []; S.elements = []; S.pdfProcessed = false;
  action = 'show_lang';
}
else if (text.toLowerCase() === '/help') {
  action = 'show_help';
}

// === LANGUAGE SELECTION ===
else if (/^lang_(DE|EN|RU|ES|FR|PT|ZH|AR|HI)$/i.test(callbackData)) {
  S.lang = callbackData.replace('lang_', '').toUpperCase();
  S.state = 'wait_photo'; action = 'lang_selected';
}

// ═══════════════════════════════════════════════════════════════════════════
// PDF HANDLING
// ═══════════════════════════════════════════════════════════════════════════
else if (hasPDF && S.lang) {
  S.pdfFileId = pdfFileId;
  S.pdfFileName = pdfFileName;
  S.state = 'processing_pdf';
  S.description = `📄 ${pdfFileName}`;
  action = 'process_pdf';
}

// === PHOTO HANDLING (Multi-photo support) ===
else if (hasImage && S.lang) {
  S.photos.push({ fileId, caption });
  if (caption) S.description = caption;

  if (mediaGroupId) {
    S.mediaGroupId = mediaGroupId;
    S.state = 'collecting_photos';
    action = 'photo_added';
  } else {
    S.state = 'ready_to_analyze';
    action = 'show_analyze_options';
  }
}

// === VOICE MESSAGE ===
else if (hasVoice && S.lang) {
  S.voiceFileId = voiceFileId;
  S.state = 'processing_voice';
  action = 'process_voice';
}

// === ANALYZE BUTTON ===
else if (callbackData === 'analyze_photos') {
  if (S.photos.length > 0) {
    S.state = 'analyzing';
    action = 'analyze';
  } else {
    action = 'ask_photo';
  }
}

// === ADD MORE PHOTOS ===
else if (callbackData === 'add_more_photos') {
  S.state = 'wait_photo';
  action = 'ask_photo';
}

// === CATEGORY FILTERS ===
else if (/^cat_(demolition|rough|finishing|mep)$/.test(callbackData)) {
  const cat = callbackData.replace('cat_', '');
  S.categories[cat] = !S.categories[cat];
  action = 'update_categories';
}

// === EDIT WORK ITEMS ===
else if (/^edit_work_(\d+)$/.test(callbackData)) {
  const idx = parseInt(callbackData.match(/edit_work_(\d+)/)[1]);
  S.editingWorkIndex = idx;
  S.state = 'editing_work';
  action = 'show_edit_menu';
}
else if (/^delete_work_(\d+)$/.test(callbackData)) {
  const idx = parseInt(callbackData.match(/delete_work_(\d+)/)[1]);
  if (S.works[idx]) {
    S.works.splice(idx, 1);
    S.works.forEach((w, i) => { w.seq = i + 1; w.id = `W${String(i+1).padStart(3,'0')}`; });
  }
  action = 'works_updated';
}
else if (/^qty_work_(\d+)_(.+)$/.test(callbackData)) {
  const match = callbackData.match(/qty_work_(\d+)_(.+)/);
  const idx = parseInt(match[1]);
  const change = match[2];
  if (S.works[idx]) {
    let q = S.works[idx].qty;
    if (change === 'plus10') q += 10;
    else if (change === 'minus10') q = Math.max(1, q - 10);
    else if (change === 'plus1') q += 1;
    else if (change === 'minus1') q = Math.max(1, q - 1);
    else if (change === 'double') q *= 2;
    else if (change === 'half') q = Math.max(1, Math.round(q / 2));
    S.works[idx].qty = q;
  }
  action = 'works_updated';
}
else if (callbackData === 'add_work') {
  S.state = 'adding_work';
  action = 'ask_new_work';
}
else if (callbackData === 'done_editing') {
  S.state = 'works_shown';
  action = 'works_updated';
}

// === CALCULATE ===
else if (callbackData === 'refine_analysis') {
  action = 'refine_analysis';
}
else if (callbackData === 'calculate') {
  if (S.works && S.works.length > 0) {
    S.state = 'calc';
    action = 'start_calc';
  } else {
    action = 'ask_photo';
  }
}

// === EXPORT OPTIONS ===
else if (callbackData === 'view_details') {
  action = 'view_details';
}
else if (callbackData === 'export_excel') {
  action = 'export_excel';
}
else if (callbackData === 'export_pdf') {
  action = 'export_pdf';
}

// === NEW ESTIMATE / RESTART ===
else if (callbackData === 'new_photo' || callbackData === 'new_estimate' || callbackData === 'restart') {
  S.photos = []; S.works = []; S.voiceText = ''; S.description = '';
  S.pdfFileId = null; S.pdfFileName = null; S.rooms = []; S.elements = []; S.pdfProcessed = false;
  S.state = 'wait_photo';
  action = 'ask_photo';
}
else if (callbackData === 'show_help' || callbackData === 'help') {
  action = 'show_help';
}
else if (callbackData === 'change_language') {
  S.lang = null; S.state = 'wait_lang';
  action = 'show_lang';
}

// === TEXT INPUT (for adding work) ===
else if (text && S.state === 'adding_work') {
  const parts = text.split(',');
  const name = parts[0]?.trim() || text;
  let qty = 1, unit = 'm²';
  if (parts[1]) {
    const qtyMatch = parts[1].match(/([\d.,]+)\s*(.*)/);
    if (qtyMatch) {
      qty = parseFloat(qtyMatch[1].replace(',', '.')) || 1;
      unit = qtyMatch[2]?.trim() || 'm²';
    }
  }
  const newWork = {
    id: `W${String(S.works.length + 1).padStart(3,'0')}`,
    name, query: name, qty, unit, conf: 'medium', category: 'general', seq: S.works.length + 1
  };
  S.works.push(newWork);
  S.state = 'works_shown';
  action = 'works_updated';
}

// === FALLBACKS ===
else if (!S.lang) { action = 'show_lang'; }
else if (S.state === 'wait_photo' && !hasImage && !hasPDF && text && text.length > 5) {
  S.description = text;
  S.textInput = text;
  S.photos = S.photos || [];
  action = 'analyze_text';
}
else if (S.state === 'wait_photo' && !hasImage && !hasPDF) { action = 'ask_photo'; }
else if (S.state === 'collecting_photos') {
  action = 'none';
}

return { json: { 
  bot_token: botToken, chatId, action, lang: S.lang, works: S.works, 
  callbackData, callbackQueryId, isCallback, hasImage, hasVoice, 
  fileId, voiceFileId, text, caption, photos: S.photos,
  categories: S.categories, editingWorkIndex: S.editingWorkIndex,
  description: S.description, voiceText: S.voiceText,
  // PDF fields
  hasPDF, pdfFileId, pdfFileName,
  rooms: S.rooms, elements: S.elements, pdfProcessed: S.pdfProcessed
}};

// ═══════════════════════════════════════════════════════════════════════════
// DDC CWICR - Refine analysis with advanced prompt
// FIXED: Check if photos are available before proceeding
// ═══════════════════════════════════════════════════════════════════════════

const cfg = $('Config').first().json;
const cid = String(cfg.chatId);
const sd = $getWorkflowStaticData('global');
const session = sd.sess?.[cid] || {};
const L = cfg.L || session.L || {};

console.log('=== REFINE ANALYSIS ===');
console.log('Session keys:', Object.keys(session));
console.log('photos_base64:', session.photos_base64?.length || 0);
console.log('photos:', (cfg.photos || session.photos || []).length);

// ═══════════════════════════════════════════════════════════════════════════
// ПРОВЕРЯЕМ: есть ли фотографии для анализа?
// ═══════════════════════════════════════════════════════════════════════════
const hasStoredBase64 = session.photos_base64 && session.photos_base64.length > 0;
const hasPhotoFileIds = (cfg.photos && cfg.photos.length > 0) || (session.photos && session.photos.length > 0);

console.log('hasStoredBase64:', hasStoredBase64);
console.log('hasPhotoFileIds:', hasPhotoFileIds);

if (!hasStoredBase64 && !hasPhotoFileIds) {
  console.log('No photos available for refinement - will ask user');

  if (!sd.sess) sd.sess = {};
  if (!sd.sess[cid]) sd.sess[cid] = {};
  sd.sess[cid].state = 'wait_photo';

  return { json: { 
    ...cfg, 
    chatId: cid,
    skipRefine: true,
    noPhotos: true,
    L 
  }};
}

console.log('Photos available - proceeding with refine');

if (!sd.sess) sd.sess = {};
if (!sd.sess[cid]) sd.sess[cid] = {};
sd.sess[cid].use_advanced_prompt = true;

return { json: { 
  ...cfg, 
  chatId: cid,
  use_advanced_prompt: true, 
  skipRefine: false,
